EmptyDataBind.SQL:
DECLARE @PermissionIDs dbo.ListNVarchar100Type; INSERT INTO @PermissionIDs VALUES ('ITSMAuthor'), ('ITSMOperator');
DECLARE @OperatorOnlyPermissionIDs dbo.ListNVarchar100Type; INSERT INTO @OperatorOnlyPermissionIDs VALUES ('ITSMOperator');
IF(@ReporterAccountID IS NULL OR @ReporterAccountID = @UserID)
SELECT TOP(20) itsmFolPer.FolderTreeIdent AS Ident ,itsmFolPer.FolderName AS [Name] FROM usr.ITSM_GetAllowedFolderTreeByAccountAndPermissionAndSegmentType(@UserID,@FolderGroupSegmentIdent,'{{FormIdent}}Segment',@PermissionIDs) as itsmFolPer WHERE itsmFolPer.FolderLevel = @Level AND itsmFolPer.FolderState = @FolderActiveState
ELSE
SELECT TOP(20) itsmFolPer.FolderTreeIdent AS Ident ,itsmFolPer.FolderName AS [Name] FROM usr.ITSM_GetAllowedFolderTreeByAccountAndPermissionAndSegmentType(@UserID,@FolderGroupSegmentIdent,'{{FormIdent}}Segment',@OperatorOnlyPermissionIDs) as itsmFolPer INNER JOIN usr.ITSM_GetAllowedFolderTreeByAccountAndPermissionAndSegmentType(@ReporterAccountID,@FolderGroupSegmentIdent,'{{FormIdent}}Segment',@PermissionIDs) as itsmFolPerReporter ON itsmFolPerReporter.FolderTreeID = itsmFolPer.FolderTreeID WHERE itsmFolPer.FolderLevel = @Level AND itsmFolPer.FolderState = @FolderActiveState

DataBind.SQL:
DECLARE @PermissionIDs dbo.ListNVarchar100Type; INSERT INTO @PermissionIDs VALUES ('ITSMAuthor'), ('ITSMOperator');
DECLARE @OperatorOnlyPermissionIDs dbo.ListNVarchar100Type; INSERT INTO @OperatorOnlyPermissionIDs VALUES ('ITSMOperator');
IF(@ReporterAccountID IS NULL OR @ReporterAccountID = @UserID)
SELECT itsmFolPer.FolderTreeIdent AS Ident ,itsmFolPer.FolderName AS [Name] FROM usr.ITSM_GetAllowedFolderTreeByAccountAndPermissionAndSegmentType(@UserID,@FolderGroupSegmentIdent,'{{FormIdent}}Segment',@PermissionIDs) as itsmFolPer WHERE itsmFolPer.FolderLevel = @Level AND itsmFolPer.FolderState = @FolderActiveState AND itsmFolPer.FolderName LIKE @ITSMCompanyIdent
ELSE
SELECT itsmFolPer.FolderTreeIdent AS Ident ,itsmFolPer.FolderName AS [Name] FROM usr.ITSM_GetAllowedFolderTreeByAccountAndPermissionAndSegmentType(@UserID,@FolderGroupSegmentIdent,'{{FormIdent}}Segment',@OperatorOnlyPermissionIDs) as itsmFolPer INNER JOIN usr.ITSM_GetAllowedFolderTreeByAccountAndPermissionAndSegmentType(@ReporterAccountID,@FolderGroupSegmentIdent,'{{FormIdent}}Segment',@PermissionIDs) as itsmFolPerReporter ON itsmFolPerReporter.FolderTreeID = itsmFolPer.FolderTreeID WHERE itsmFolPer.FolderLevel = @Level AND itsmFolPer.FolderState = @FolderActiveState AND itsmFolPer.FolderName LIKE @ITSMCompanyIdent
